1	// Playwright smoke test for ddx-9ce6842a AC §8.
2	//
3	// These tests measure wall-clock time from page.goto to "list is
4	// interactive" against a mocked GraphQL layer that returns a realistic-
5	// sized payload (50 beads — the default page window). They are ceilings,
6	// not p95 targets: the gate catches outright regressions (runaway render
7	// loops, missing virtualization, blocking scripts) without tying the
8	// repo's green/red status to machine speed.
9	//
10	// The matching server-side ceilings (GraphQL response under the same
11	// budget on the real fixture) are enforced in
12	// cli/internal/server/perf/smoke_test.go — together they guard the full
13	// round-trip the user feels.
14	import { expect, test } from '@playwright/test';
15	
16	const NODE_INFO = { id: 'node-smoke', name: 'smoke node' };
17	const PROJECT_ID = 'proj-smoke';
18	const PROJECTS = [{ id: PROJECT_ID, name: 'Smoke project', path: '/repos/smoke' }];
19	
20	function generateBeads(count: number) {
21		const beads = [];
22		for (let i = 0; i < count; i++) {
23			beads.push({
24				id: `ddx-smoke-${String(i).padStart(4, '0')}`,
25				title: `Smoke fixture bead ${i}`,
26				status: i % 3 === 0 ? 'closed' : 'open',
27				priority: i % 4,
28				labels: ['smoke', `bucket-${i % 7}`]
29			});
30		}
31		return beads;
32	}
33	
34	async function mockSmokeGraphQL(page: import('@playwright/test').Page, beadCount: number) {
35		const beads = generateBeads(beadCount);
36		await page.route('/graphql', async (route) => {
37			const body = route.request().postDataJSON() as { query: string };
38			if (body.query.includes('beadsByProject')) {
39				await route.fulfill({
40					status: 200,
41					contentType: 'application/json',
42					body: JSON.stringify({
43						data: {
44							beadsByProject: {
45								edges: beads.map((b, i) => ({ node: b, cursor: `cursor-${i}` })),
46								pageInfo: { hasNextPage: false, endCursor: null },
47								totalCount: beads.length
48							}
49						}
50					})
51				});
52			} else if (body.query.includes('beads(')) {
53				// Cross-project list fetches the `beads` field.
54				await route.fulfill({
55					status: 200,
56					contentType: 'application/json',
57					body: JSON.stringify({
58						data: {
59							beads: {
60								edges: beads.map((b, i) => ({ node: b, cursor: `cursor-${i}` })),
61								pageInfo: { hasNextPage: false, endCursor: null },
62								totalCount: beads.length
63							},
64							projects: { edges: PROJECTS.map((p) => ({ node: p })) }
65						}
66					})
67				});
68			} else if (body.query.includes('nodeInfo')) {
69				await route.fulfill({
70					status: 200,
71					contentType: 'application/json',
72					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
73				});
74			} else if (body.query.includes('projects')) {
75				await route.fulfill({
76					status: 200,
77					contentType: 'application/json',
78					body: JSON.stringify({
79						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
80					})
81				});
82			} else {
83				await route.continue();
84			}
85		});
86	}
87	
88	// ddx-9ce6842a AC §8: per-project /beads interactive within 1s.
89	test('smoke: /beads list is interactive within 1s on 50-bead fixture', async ({ page }) => {
90		await mockSmokeGraphQL(page, 50);
91	
92		const start = Date.now();
93		await page.goto(`/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/beads`);
94		// "Interactive" = the heading has rendered AND at least one bead row is
95		// visible (so clicking it would navigate). Both are prerequisites to a
96		// real user clicking anything.
97		await expect(page.getByRole('heading', { name: 'Beads' })).toBeVisible({ timeout: 1000 });
98		await expect(page.getByText('Smoke fixture bead 0')).toBeVisible({ timeout: 1000 });
99		const elapsed = Date.now() - start;
100		expect(elapsed, `per-project /beads interactive in ${elapsed}ms (ceiling 1000ms)`).toBeLessThan(
101			1000
102		);
103	});
104	
105	// ddx-9ce6842a AC §8: cross-project /beads interactive within 2s.
106	// We drive the same list view with 300 rows to mimic the cross-project
107	// aggregate load — the backend ceiling is wider (2s) because the real call
108	// is beads() with no projectID.
109	test('smoke: cross-project /beads list is interactive within 2s on 300-bead fixture', async ({
110		page
111	}) => {
112		await mockSmokeGraphQL(page, 300);
113	
114		const start = Date.now();
115		await page.goto(`/nodes/${NODE_INFO.id}/beads`);
116		await expect(page.getByRole('heading', { name: 'Beads' })).toBeVisible({ timeout: 2000 });
117		await expect(page.getByText('Smoke fixture bead 0')).toBeVisible({ timeout: 2000 });
118		const elapsed = Date.now() - start;
119		expect(elapsed, `cross-project /beads interactive in ${elapsed}ms (ceiling 2000ms)`).toBeLessThan(
120			2000
121		);
122	});
